void lightSound() => SystemSound.play(SystemSoundType.click);
const devEmail = 'fastunlocked2017@gmail.com';
void copyDevMessage(BuildContext context, String appName) {
  final msg = 'مرحبًا، لدي ملاحظة حول تطبيق $appName.\nالبريد: $devEmail';
  Clipboard.setData(ClipboardData(text: msg));
  lightSound();
  ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('تم نسخ رسالة المطور')));
}
TextStyle get titleStyle => const TextStyle(fontSize: 24, fontWeight: FontWeight.w900);

void main() => runApp(const DebtApp());
class DebtApp extends StatelessWidget { const DebtApp({super.key}); @override Widget build(BuildContext context)=>MaterialApp(debugShowCheckedModeBanner:false,locale:const Locale('ar'),supportedLocales:const[Locale('ar')],localizationsDelegates:GlobalMaterialLocalizations.delegates,theme:ThemeData(useMaterial3:true,fontFamily:'Arial'),home:const DebtHome());}
class DebtHome extends StatefulWidget{const DebtHome({super.key});@override State<DebtHome> createState()=>_DebtHomeState();}
class _DebtHomeState extends State<DebtHome>{final name=TextEditingController();final amount=TextEditingController();final note=TextEditingController();List<Map<String,dynamic>> items=[];@override void initState(){super.initState();load();}Future<void>load()async{final p=await SharedPreferences.getInstance();items=List<Map<String,dynamic>>.from((jsonDecode(p.getString('items')??'[]') as List).map((e)=>Map<String,dynamic>.from(e)));setState((){});}Future<void>save()async{final p=await SharedPreferences.getInstance();await p.setString('items',jsonEncode(items));}double get totalForMe=>items.where((e)=>e['type']=='لي').fold(0.0,(s,e)=>s+(e['amount'] as num));double get totalOnMe=>items.where((e)=>e['type']=='علي').fold(0.0,(s,e)=>s+(e['amount'] as num));void add(String type){final v=double.tryParse(amount.text.trim())??0;if(name.text.trim().isEmpty||v<=0)return;items.insert(0,{'name':name.text.trim(),'amount':v,'note':note.text.trim(),'type':type,'date':DateTime.now().toString().substring(0,10)});name.clear();amount.clear();note.clear();save();lightSound();setState((){});} @override Widget build(BuildContext context)=>Directionality(textDirection:TextDirection.rtl,child:Scaffold(backgroundColor:const Color(0xfff5f1ea),body:SafeArea(child:ListView(padding:const EdgeInsets.all(18),children:[Container(padding:const EdgeInsets.all(20),decoration:BoxDecoration(gradient:const LinearGradient(colors:[Color(0xff4b3621),Color(0xffa07645)]),borderRadius:BorderRadius.circular(28)),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[const Text('دفتر الديون الذكي',style:TextStyle(color:Colors.white,fontSize:26,fontWeight:FontWeight.w900)),const SizedBox(height:8),Text('الصافي: ${(totalForMe-totalOnMe).toStringAsFixed(2)}',style:const TextStyle(color:Colors.white,fontSize:20)),const SizedBox(height:14),Row(children:[Expanded(child:_pill('لي عنده',totalForMe)),const SizedBox(width:10),Expanded(child:_pill('علي',totalOnMe))])])),const SizedBox(height:16),_field(name,'اسم الشخص'),_field(amount,'المبلغ',num:true),_field(note,'ملاحظة'),Row(children:[Expanded(child:FilledButton(onPressed:()=>add('لي'),child:const Text('إضافة لي'))),const SizedBox(width:10),Expanded(child:OutlinedButton(onPressed:()=>add('علي'),child:const Text('إضافة علي')))]),const SizedBox(height:16),...items.map((e)=>Card(child:ListTile(title:Text('${e['name']} - ${e['type']}',style:const TextStyle(fontWeight:FontWeight.bold)),subtitle:Text('${e['date']}  ${e['note']}'),trailing:Text((e['amount'] as num).toStringAsFixed(2)),onLongPress:(){items.remove(e);save();lightSound();setState((){});},))),const Divider(),ListTile(title:const Text('مراسلة المطور'),subtitle:const Text(devEmail),trailing:const Icon(Icons.copy),onTap:()=>copyDevMessage(context,'دفتر الديون الذكي'))]))));Widget _pill(String t,double v)=>Container(padding:const EdgeInsets.all(12),decoration:BoxDecoration(color:Colors.white.withValues(alpha:.18),borderRadius:BorderRadius.circular(18)),child:Column(children:[Text(t,style:const TextStyle(color:Colors.white70)),Text(v.toStringAsFixed(2),style:const TextStyle(color:Colors.white,fontWeight:FontWeight.w900,fontSize:18))]));Widget _field(TextEditingController c,String h,{bool num=false})=>Padding(padding:const EdgeInsets.only(bottom:10),child:TextField(controller:c,keyboardType:num?TextInputType.number:null,decoration:InputDecoration(filled:true,fillColor:Colors.white,labelText:h,border:OutlineInputBorder(borderRadius:BorderRadius.circular(18),borderSide:BorderSide.none))));}
